import { create } from 'zustand'

export interface SaleItem {
  id: string
  name: string
  price: number
  qty: number
  costPrice?: number
}

export interface Sale {
  id: string
  items: SaleItem[]
  subtotal: number
  tax: number
  discount: number
  total: number
  paymentMethod: 'cash' | 'gcash' | 'card'
  date: Date
}

export interface SalesStore {
  sales: Sale[]
  addSale: (sale: Omit<Sale, 'id' | 'date'>) => void
  getSalesForPeriod: (startDate: Date, endDate: Date) => Sale[]
  getSalesForLast30Days: () => Sale[]
  getGrossIncome: (startDate: Date, endDate: Date) => number
  getNetIncome: (startDate: Date, endDate: Date) => number
  getDailySalesData: (days: number) => Array<{ date: string; total: number; count: number }>
}

export const useSalesStore = create<SalesStore>((set, get) => ({
  sales: [],
  
  addSale: (sale) => {
    const newSale: Sale = {
      ...sale,
      id: Date.now().toString(),
      date: new Date()
    }
    set((state) => ({
      sales: [...state.sales, newSale]
    }))
  },
  
  getSalesForPeriod: (startDate, endDate) => {
    const { sales } = get()
    return sales.filter(sale => {
      const saleDate = new Date(sale.date)
      return saleDate >= startDate && saleDate <= endDate
    })
  },
  
  getSalesForLast30Days: () => {
    const endDate = new Date()
    const startDate = new Date()
    startDate.setDate(startDate.getDate() - 30)
    return get().getSalesForPeriod(startDate, endDate)
  },
  
  getGrossIncome: (startDate, endDate) => {
    const sales = get().getSalesForPeriod(startDate, endDate)
    return sales.reduce((total, sale) => total + sale.total, 0)
  },
  
  getNetIncome: (startDate, endDate) => {
    const sales = get().getSalesForPeriod(startDate, endDate)
    return sales.reduce((total, sale) => {
      const costOfGoods = sale.items.reduce((cost, item) => {
        return cost + (item.costPrice ? item.costPrice * item.qty : 0)
      }, 0)
      return total + (sale.total - costOfGoods)
    }, 0)
  },
  
  getDailySalesData: (days: number) => {
    const endDate = new Date()
    const startDate = new Date()
    startDate.setDate(startDate.getDate() - days)
    
    const sales = get().getSalesForPeriod(startDate, endDate)
    const dailyData = new Map<string, { total: number; count: number }>()
    
    // Initialize all days with zero
    for (let i = 0; i <= days; i++) {
      const date = new Date()
      date.setDate(date.getDate() - i)
      const dateStr = date.toISOString().split('T')[0]
      dailyData.set(dateStr, { total: 0, count: 0 })
    }
    
    // Aggregate sales by date
    sales.forEach(sale => {
      const dateStr = new Date(sale.date).toISOString().split('T')[0]
      const existing = dailyData.get(dateStr) || { total: 0, count: 0 }
      dailyData.set(dateStr, {
        total: existing.total + sale.total,
        count: existing.count + 1
      })
    })
    
    // Convert to array and sort by date
    return Array.from(dailyData.entries())
      .map(([date, data]) => ({
        date: new Date(date).toLocaleDateString('en-PH', { month: 'short', day: 'numeric' }),
        total: data.total,
        count: data.count
      }))
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
  }
}))